import { Command } from 'commander';
import { registerBughunterCommand } from './commands/bughunter.js';

const program = new Command();
program.name('agnt').description('ShadowTag Agent Runtime CLI').version('11.2.0');
registerBughunterCommand(program);
program.parseAsync(process.argv).catch((err) => { console.error(err.message); process.exit(1); });
